@page "/edit-person"
@using FluentValidation

<EditForm Model="@_model" OnValidSubmit="HandleValidSubmit" OnInvalidSubmit="HandleInvalidSubmit">
    <FluentValidationValidator />

    <TmValidationSummary />

    <TmFormSection Title="Personal Information" class="mb-6">
        <TmFormRow Columns="2">
            <TmValidatedField Label="First Name" Required="true"
                @bind-Value="_model.FirstName" Placeholder="Enter first name" />
            <TmValidatedField Label="Last Name" Required="true"
                @bind-Value="_model.LastName" Placeholder="Enter last name" />
        </TmFormRow>
        <TmFormRow Columns="2">
            <TmValidatedField Label="Email" Required="true" Type="email"
                @bind-Value="_model.Email" Placeholder="user@example.com"
                LeftIcon="@IconNames.Mail" />
            <TmFormField Label="Age" Required="true">
                <TmNumberInput @bind-Value="_model.Age" Min="18" Max="120" />
                <TmFormValidationMessage For="@(() => _model.Age)" />
            </TmFormField>
        </TmFormRow>
    </TmFormSection>

    <TmFormSection Title="Work Details" Collapsible="true" class="mb-6">
        <TmFormRow Columns="2">
            <TmFormField Label="Department" Required="true">
                <TmSelect TValue="string" @bind-Value="_model.Department"
                    Options="@_departmentOptions" Placeholder="Select department" />
                <TmFormValidationMessage For="@(() => _model.Department)" />
            </TmFormField>
            <TmFormField Label="Start Date" Required="true">
                <TmDatePicker @bind-Value="_model.StartDate" />
                <TmFormValidationMessage For="@(() => _model.StartDate)" />
            </TmFormField>
        </TmFormRow>
        <TmFormRow Columns="2">
            <TmFormField Label="End Date">
                <TmDatePicker @bind-Value="_model.EndDate" />
                <TmFormValidationMessage For="@(() => _model.EndDate)" />
            </TmFormField>
        </TmFormRow>
    </TmFormSection>

    <div style="display: flex; gap: 0.5rem;">
        <TmButton Type="ButtonType.Submit" Variant="ButtonVariant.Primary"
            IsLoading="@_isSaving">Save</TmButton>
        <TmButton Variant="ButtonVariant.Ghost" OnClick="Cancel">Cancel</TmButton>
    </div>
</EditForm>

@code {
    private PersonFormModel _model = new();
    private bool _isSaving;

    private List<SelectOption<string>> _departmentOptions = new()
    {
        new("engineering", "Engineering"),
